function buildOrder(n, edges) {
  const adj = Array.from({ length: n }, () => []);
  const indeg = new Array(n).fill(0);
  const seen = new Set();
  for (const [a, b] of edges) {
    const key = a * n + b;
    if (seen.has(key)) continue;
    seen.add(key);
    adj[a].push(b);
    indeg[b]++;
  }

  // Min-heap for lexicographically smallest ordering
  const heap = [];
  const push = (v) => {
    heap.push(v);
    let i = heap.length - 1;
    while (i > 0) {
      const p = (i - 1) >> 1;
      if (heap[p] <= heap[i]) break;
      [heap[p], heap[i]] = [heap[i], heap[p]];
      i = p;
    }
  };
  const pop = () => {
    const top = heap[0];
    const last = heap.pop();
    if (heap.length) {
      heap[0] = last;
      let i = 0;
      while (true) {
        const l = 2 * i + 1, r = 2 * i + 2;
        let s = i;
        if (l < heap.length && heap[l] < heap[s]) s = l;
        if (r < heap.length && heap[r] < heap[s]) s = r;
        if (s === i) break;
        [heap[s], heap[i]] = [heap[i], heap[s]];
        i = s;
      }
    }
    return top;
  };

  for (let i = 0; i < n; i++) if (indeg[i] === 0) push(i);

  const order = [];
  while (heap.length) {
    const u = pop();
    order.push(u);
    for (const v of adj[u]) {
      if (--indeg[v] === 0) push(v);
    }
  }

  return order.length === n ? order : null;
}
